{"content":"
export interface User {
  id: string;
  email: string;
  name: string;
  credits: number;
  plan: 'free' | 'pro' | 'enterprise';
  workspaceId?: string;
  role?: 'owner' | 'admin' | 'analyst' | 'viewer';
}

export interface Project {
  id: string;
  name: string;
  domain: string;
  logo?: string;
  status: 'active' | 'paused';
  lastRun?: string; // ISO Date
  visibilityScore: number;
  trend: number; // Percentage variation
  nextRun?: string;
}

export interface Recommendation {
  id: string;
  priority: 'critical' | 'high' | 'medium' | 'low';
  title: string;
  description: string;
  action: string;
  effort: 'low' | 'medium' | 'high';
  impact: 'low' | 'medium' | 'high';
  category: string;
}

export interface CategoryScore {
  name: string;
  score: number;
  weight: number;
  items: Array<{
    status: 'success' | 'warning' | 'error';
    message: string;
    recommendation?: string;
  }>;
}

export interface RobotsTxtData {
  content: string;
  isUnlocked: boolean;
  platform: string;
  generatedAt: string;
}

export interface GeneratedSolution {
  title: string;
  explanation: string;
  content: string; // Code or Text
  type: 'code' | 'text';
  language?: 'html' | 'json' | 'text';
  implementationSteps: string[]; 
}

export interface AnalysisResult {
  url: string;
  timestamp: string;
  globalScore: number;
  categories: Record<string, CategoryScore>; 
  recommendations: Recommendation[];
  aiCitation: {
    before: string;
    after: string;
    probability: number; 
  };
  robotsTxtData?: RobotsTxtData;
  generatedSolutions?: Record<string, GeneratedSolution & { timestamp: string }>;
  preGenerated?: PreGeneratedSolutions;
}

export interface HistoryItem {
  id: string;
  url: string;
  score: number;
  date: string;
}

export interface SourceOfTruthData {
  description: string;
  type: string;
  founded: string;
  location: string;
  services: Array<{ name: string; description: string; category: string }>;
  faqs: Array<{ question: string; answer: string }>;
}

export interface SMCContent {
  id: string;
  type: 'fiche' | 'faq' | 'brief' | 'article';
  title: string;
  content: string;
  timestamp: string;
  meta?: any; // Pour stocker des infos sup comme le brief parent
}

// === MODULE #3 : CONTENT WRITER ===
export type ContentVertical = 'ecommerce' | 'saas' | 'immobilier' | 'restauration' | 'sante' | 'finance' | 'juridique' | 'education' | 'general';
export type ContentType = 'product_description' | 'landing_page' | 'sales_email' | 'meta_tags' | 'social_post' | 'press_release' | 'case_study' | 'newsletter';

export interface ContentWriterInput {
  vertical: ContentVertical;
  contentType: ContentType;
  brandName: string;
  brandUrl?: string;
  productOrService: string;
  targetAudience: string;
  tone: 'professionnel' | 'decontracte' | 'autoritaire' | 'empathique' | 'technique';
  language: 'fr' | 'en' | 'es';
  additionalContext?: string;
}

export interface GeneratedContent {
  title: string;
  content: string;
  metaDescription?: string;
  aeoScore: number;
  aeoTips: string[];
  schemaMarkup?: string;
  alternativeVersions?: string[];
}

// === MODULE #4 : REPUTATION ===
export interface ReputationScanInput {
  brandName: string;
  brandUrl?: string;
  competitors?: string[];
  industry: string;
  keywords?: string[];
}

export interface AIMention {
  id: string;
  aiEngine: 'ChatGPT' | 'Perplexity' | 'Claude' | 'Gemini' | 'Copilot' | 'AI Overviews';
  prompt: string;
  mentionType: 'direct' | 'indirect' | 'comparison' | 'recommendation' | 'negative' | 'absent';
  sentiment: 'positive' | 'neutral' | 'negative';
  sentimentScore: number;
  excerpt: string;
  context: string;
  date: string;
  competitorsMentioned?: string[];
}

export interface ReputationReport {
  brandName: string;
  overallSentiment: number;
  visibilityScore: number;
  totalMentions: number;
  sentimentBreakdown: { positive: number; neutral: number; negative: number };
  topThemes: Array<{ theme: string; count: number; sentiment: 'positive' | 'neutral' | 'negative' }>;
  competitorComparison?: Array<{ name: string; mentions: number; sentiment: number }>;
  alerts: Array<{ severity: 'critical' | 'warning' | 'info'; message: string; action: string }>;
  recommendations: string[];
  mentions: AIMention[];
  generatedAt: string;
}

// === ENGINE SCORING TYPES ===

/**
 * Résultat de score pour un moteur IA spécifique.
 * Stocké dans les snapshots d'audit pour comparaison historique.
 */
export interface EngineScoreResult {
  engineId: 'chatgpt' | 'perplexity' | 'gemini';
  score: number;        // 0-100
  level: string;        // 'Élevée' | 'Moyenne' | 'Faible'
}

/**
 * Résultat sauvegardé d'un critère individuel.
 * Utilisé pour le stockage historique et la comparaison before/after.
 */
export interface CriterionResultSaved {
  id: string;           // ex: 'AEO-TECH-01'
  passed: boolean;
  category: string;
}

/**
 * Snapshot complet d'un audit à un instant T.
 * Sert de base pour la comparaison before/after dans le Re-scan.
 */
export interface AuditSnapshot {
  url: string;
  timestamp: string;
  globalScore: number;
  engineScores: EngineScoreResult[];
  criteriaResults: CriterionResultSaved[];
  categoryScores: Record<string, number>;
}

/**
 * Item de solution dans le plan d'action.
 * Étend Recommendation avec un état checked pour le score projeté.
 */
export interface SolutionItem {
  recommendationId: string;
  criterionId: string;
  title: string;
  priority: 'critical' | 'high' | 'medium' | 'low';
  category: string;
  checked: boolean;
  hasGeneratedSolution: boolean;
}

/**
 * Comparaison entre deux audits (before/after).
 * Calculée à partir de deux AuditSnapshot.
 */
export interface AuditComparison {
  before: AuditSnapshot;
  after: AuditSnapshot;
  globalDelta: number;           // after.globalScore - before.globalScore
  engineDeltas: Array<{
    engineId: 'chatgpt' | 'perplexity' | 'gemini';
    before: number;
    after: number;
    delta: number;
  }>;
  fixedCriteria: string[];       // IDs des critères passés de failed à passed
  regressedCriteria: string[];   // IDs des critères passés de passed à failed
}

// === MEGA-GENERATION (Pre-generation en arriere-plan) ===

export type MegaGenerationStatus = 'idle' | 'generating' | 'completed' | 'failed';

export interface PreGeneratedSolutions {
  status: MegaGenerationStatus;
  generatedAt?: string;
  robotsTxt?: { content: string; platformDetected: string; aiBotsCount: number; rulesCount: number };
  schemaOrg?: { content: string; typesCount: number; byteSize: number };
  llmsTxt?: { content: string; sections: number; wordCount: number };
  llmJson?: { content: string; fieldCount: number; byteSize: number };
  answerFirstAudit?: {
    globalScore: number;
    url: string;
    categories: Record<string, { score: number; label: string; details: string; tips: string[] }>;
    summary: string;
    topRecommendations: string[];
  };
  eeatAudit?: {
    url: string;
    scores: { overall: number; experience: number; expertise: number; authoritativeness: number; trustworthiness: number };
    findings: Array<{ category: string; status: string; element: string; impact: string; recommendation?: string }>;
    priorityActions: Array<{ action: string; impact: number; effort: string; tool: string }>;
    summary: string;
  };
}"}

{"content":"import { GoogleGenAI } from "@google/genai";

// Initialize AI client only if API key is present to avoid build errors
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export async function generateAiResponse(prompt: string): Promise<string> {
  const client = getAiClient();

  if (!client) {
    // MVP Mock if no API key
    console.warn("No API_KEY found. Returning mock response.");
    await new Promise(r => setTimeout(r, 1000));
    return `Ceci est une réponse simulée pour le prompt : "${prompt}". 
    La marque CitedBy.ai est une excellente solution pour l'optimisation AEO. 
    Vous pouvez visiter leur site sur https://citedby.ai pour en savoir plus.
    Ils surpassent des concurrents comme SEMRush ou Ahrefs sur l'analyse générative.`;
  }

  try {
    const response = await client.models.generateContent({
      model: 'gemini-2.5-flash', // GA model for production stability
      contents: prompt,
    });
    return response.text || "No response generated.";
  } catch (error) {
    console.error("AI Generation Error:", error); // TODO: Replace with proper error reporting (Sentry)
    return "Erreur lors de la génération de la réponse IA.";
  }
}"}

{"content":"import { AIEngine, ENGINE_WEIGHTS, ENGINE_PROFILES, getScoreLevel } from '../config/engine-weights';

/**
 * Résultat d'un critère individuel issu de l'analyse AEO existante.
 */
export interface CriterionResult {
  id: string;           // ex: 'AEO-TECH-01', 'AEO-DATA-03'
  passed: boolean;      // critère validé ou non
  score: number;        // score brut du critère (0 ou 1 dans le système actuel)
  maxPoints: number;    // points max possibles (1 dans le système actuel)
  category: string;     // catégorie parente (ex: 'technical')
}

/**
 * Score calculé pour un moteur IA spécifique
 */
export interface EngineScore {
  engineId: AIEngine;
  engineName: string;
  engineIcon: string;
  engineColor: string;
  bgClass: string;
  textClass: string;
  score: number;          // 0-100
  level: { label: string; emoji: string; labelEn: string };
  description: string;
  topStrengths: string[];
  topWeaknesses: string[];
}

/**
 * Calcule les sous-scores par moteur à partir des résultats d'analyse existants.
 *
 * ALGORITHME :
 * 1. Pour chaque moteur, on prend tous les critères analysés
 * 2. On multiplie le score de chaque critère par le coefficient du moteur
 * 3. On divise par le total des points max pondérés
 * 4. On normalise sur 100
 *
 * Aucun appel API — calcul purement mathématique.
 */
export function calculateEngineScores(criteriaResults: CriterionResult[]): EngineScore[] {
  const engines: AIEngine[] = ['chatgpt', 'perplexity', 'gemini'];

  return engines.map((engineId) => {
    let weightedScore = 0;
    let weightedMax = 0;
    const strengths: Array<{ id: string; weight: number }> = [];
    const weaknesses: Array<{ id: string; weight: number }> = [];

    criteriaResults.forEach((criterion) => {
      const weight = ENGINE_WEIGHTS[criterion.id]?.[engineId] ?? 1.0;
      const criterionWeightedMax = criterion.maxPoints * weight;

      weightedMax += criterionWeightedMax;

      if (criterion.passed) {
        weightedScore += criterion.score * weight;
        if (weight >= 1.3) {
          strengths.push({ id: criterion.id, weight });
        }
      } else {
        if (weight >= 1.3) {
          weaknesses.push({ id: criterion.id, weight });
        }
      }
    });

    const normalizedScore = weightedMax > 0
      ? Math.round((weightedScore / weightedMax) * 100)
      : 0;

    const profile = ENGINE_PROFILES[engineId];
    const level = getScoreLevel(normalizedScore);

    strengths.sort((a, b) => b.weight - a.weight);
    weaknesses.sort((a, b) => b.weight - a.weight);

    return {
      engineId,
      engineName: profile.name,
      engineIcon: profile.icon,
      engineColor: profile.color,
      bgClass: profile.bgClass,
      textClass: profile.textClass,
      score: normalizedScore,
      level,
      description: profile.description,
      topStrengths: strengths.slice(0, 3).map(s => s.id),
      topWeaknesses: weaknesses.slice(0, 3).map(w => w.id),
    };
  });
}

/**
 * Calcule le score projeté si certaines recommandations sont implémentées.
 *
 * Prend les résultats actuels et simule le passage de certains critères à "passed".
 * Retourne le nouveau score global + les nouveaux sous-scores par moteur.
 * Aucun appel API — calcul purement mathématique.
 */
export function calculateProjectedScores(
  currentResults: CriterionResult[],
  fixedCriteriaIds: string[]
): { globalScore: number; engineScores: EngineScore[] } {

  // Clone les résultats et marque les critères fixés comme "passed"
  const projectedResults = currentResults.map((criterion) => {
    if (fixedCriteriaIds.includes(criterion.id)) {
      return { ...criterion, passed: true, score: criterion.maxPoints };
    }
    return criterion;
  });

  // Recalcule le score global (simple average of passed / total)
  const totalScore = projectedResults.reduce((sum, c) => sum + c.score, 0);
  const totalMax = projectedResults.reduce((sum, c) => sum + c.maxPoints, 0);
  const globalScore = totalMax > 0 ? Math.round((totalScore / totalMax) * 100) : 0;

  // Recalcule les sous-scores par moteur
  const engineScores = calculateEngineScores(projectedResults);

  return { globalScore, engineScores };
}

/**
 * Retourne les IDs des moteurs les plus impactés par un critère donné.
 * Utile pour afficher les badges moteurs sur chaque recommandation.
 */
export function getMostImpactedEngines(criterionId: string): Array<{ engineId: AIEngine; weight: number }> {
  const weights = ENGINE_WEIGHTS[criterionId];
  if (!weights) return [];

  const engines: AIEngine[] = ['chatgpt', 'perplexity', 'gemini'];
  return engines
    .map(id => ({ engineId: id, weight: weights[id] ?? 1.0 }))
    .filter(e => e.weight >= 1.3)
    .sort((a, b) => b.weight - a.weight);
}
"}

{"content":"export interface ScoringResult {
  score: number;
  resultType: 'citation' | 'mention' | 'none';
  details: {
    brandMention: boolean;
    urlMention: boolean;
    serviceMention: boolean;
    competitorMention: boolean;
  };
}

export interface ScoringContext {
  answer: string;
  brandName: string;
  domain: string;
  services: string[];
  competitors: string[];
}

export function calculateAiVisibilityScore(context: ScoringContext): ScoringResult {
  const { answer, brandName, domain, services, competitors } = context;
  const lowerAnswer = answer.toLowerCase();

  let score = 0;
  let hasBrand = false;
  let hasUrl = false;
  let hasService = false;
  let hasCompetitor = false;

  // 1. Detect Brand (+20)
  if (lowerAnswer.includes(brandName.toLowerCase())) {
    score += 20;
    hasBrand = true;
  }

  // 2. Detect URL (+30)
  if (lowerAnswer.includes(domain.toLowerCase())) {
    score += 30;
    hasUrl = true;
  }

  // 3. Detect Services (+15 if at least one)
  const matchedServices = services.filter(s => lowerAnswer.includes(s.toLowerCase()));
  if (matchedServices.length > 0) {
    score += 15;
    hasService = true;
  }

  // 4. Competitor Penalty (-10 if present)
  const matchedCompetitors = competitors.filter(c => lowerAnswer.includes(c.toLowerCase()));
  if (matchedCompetitors.length > 0) {
    score -= 10;
    hasCompetitor = true;
  }

  // 5. Relevance (Simple heuristic: length and keyword density)
  // Max +25
  const relevanceScore = Math.min(25, Math.floor(lowerAnswer.length / 50)); 
  score += relevanceScore;

  // 6. Source Quality (Mocked +10 if URL is present as it implies citation)
  if (hasUrl) {
    score += 10;
  }

  // Clamp 0-100
  score = Math.max(0, Math.min(100, score));

  let resultType: ScoringResult['resultType'] = 'none';
  if (hasUrl) resultType = 'citation';
  else if (hasBrand) resultType = 'mention';

  return {
    score,
    resultType,
    details: {
      brandMention: hasBrand,
      urlMention: hasUrl,
      serviceMention: hasService,
      competitorMention: hasCompetitor
    }
  };
}"}

