896→// Simple back-to-top button component
897→function BackToTopButton() {
898→  const [visible, setVisible] = useState(false);
899→  useEffect(() => {
900→    const handleScroll = () => setVisible(window.scrollY > 400);
901→    window.addEventListener('scroll', handleScroll, { passive: true });
902→    return () => window.removeEventListener('scroll', handleScroll);
903→  }, []);
904→  if (!visible) return null;
905→  return (
906→    <button
907→      onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
908→      className="fixed bottom-8 right-[5.5rem] z-40 w-10 h-10 rounded-full bg-white/[0.06] border border-white/[0.1] backdrop-blur-sm flex items-center justify-center text-gray-400 hover:text-white hover:bg-white/[0.12] transition-all duration-200"
909→      title="Retour en haut"
910→    >
911→      <ArrowUp size={16} />
912→    </button>
913→  );
914→}
915→
916→export default App;
