**The `navigateTo` function** wraps `useRouter().push()` with the `VIEW_TO_PATH` mapping:

```typescript
const navigateTo = useCallback((viewNameOrPath: string) => {
  const path = VIEW_TO_PATH[viewNameOrPath] || viewNameOrPath;
  router.push(path);
  window.scrollTo({ top: 0, behavior: 'smooth' });
}, [router]);

const goBack = useCallback(() => {
  router.back();
}, [router]);
```

**The `handleDeductCredits` function** stays the same but uses `router.push` instead of `navigateTo`:

```typescript
const handleDeductCredits = useCallback((amount: number): boolean => {
  if (!user) {
    if (confirm("Vous devez etre connecte...")) {
      router.push('/login');
    }
    return false;
  }
  if (user.credits < amount) {
    alert(`Solde GTO Gas insuffisant...`);
    router.push('/settings/recharge');
    return false;
  }
  setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
  return true;
}, [user, router]);
```

### useAppContext Hook

```typescript
export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useAppContext must be used within AppProvider');
  return context;
};
```

### Page Component Migration Pattern

Each page currently receives props like:
```typescript
// BEFORE (Vite SPA)
interface DashboardProps {
  onBack: () => void;
  history: AnalysisResult[];
  onView: (analysis: AnalysisResult) => void;
  onNavigate: (view: any) => void;
}
```

After migration, the page reads from context:
```typescript
// AFTER (Next.js)
'use client';
import { useAppContext } from '@/lib/app-context';
import { useRouter } from 'next/navigation';

export default function DashboardPage() {
  const { history, navigateTo, analysisData, setAnalysisData, setResultsTab } = useAppContext();
  const router = useRouter();

  const handleView = (analysis: AnalysisResult) => {
    setAnalysisData(analysis);
    setResultsTab('overview');
    router.push('/projects');
  };

  return <DashboardView history={history} onView={handleView} onNavigate={navigateTo} onBack={() => router.back()} />;
}
```

This pattern means we can keep the original page component code largely intact in `lib/views/` and just create thin wrapper `page.tsx` files that bridge context to props.

