// Reverse map: URL path segment to section for sidebar
export function getSectionFromPath(pathname: string): Section {
  if (pathname.startsWith('/monitoring')) return 'analyse';
  if (pathname.startsWith('/analyze') || pathname.startsWith('/projects') ||
      pathname.startsWith('/results') || pathname.startsWith('/history')) return 'analyse';
  if (pathname.startsWith('/citations')) return 'citations';
  if (pathname.startsWith('/tools')) return 'outils';
  if (pathname.startsWith('/marketplace')) return 'marketplace';
  if (pathname.startsWith('/settings')) return 'parametres';
  return 'dashboard';
}

// Get ViewName from pathname (for sidebar active state)
export function getViewNameFromPath(pathname: string): string {
  for (const [viewName, path] of Object.entries(VIEW_TO_PATH)) {
    if (path === pathname) return viewName;
  }
  return 'dashboard';
}
