 70→// Animated number hook for smooth credit transitions
 71→const useAnimatedNumber = (value: number, duration = 600) => {
 72→  const [display, setDisplay] = useState(value);
 73→  const prevValue = useRef(value);
 74→  useEffect(() => {
 75→    if (prevValue.current === value) return;
 76→    const start = prevValue.current;
 77→    const diff = value - start;
 78→    const startTime = performance.now();
 79→    const animate = (now: number) => {
 80→      const progress = Math.min((now - startTime) / duration, 1);
