import React, { useState, useMemo, useCallback, useEffect, useRef, lazy, Suspense } from 'react';
import { User, AnalysisResult, SMCContent, GeneratedSolution, MegaGenerationStatus } from './types';
import { analyzeUrl } from './services/analyzer';
import { db } from './services/database';
import { megaGenerate } from './services/mega-generator';
import { generateAllSolutions } from './services/solution-mega-generator';
import { storeInVault, hasVault } from './services/solution-vault';
import Home from './pages/Home';
import Login from './pages/Login';
import Analyze from './pages/Analyze';

// Lazy-loaded pages for bundle optimization
const Dashboard = lazy(() => import('./pages/Dashboard'));
const GenerativeTools = lazy(() => import('./pages/GenerativeTools'));
const Results = lazy(() => import('./pages/Results').then(m => ({ default: m.Results })));
const HistoryView = lazy(() => import('./pages/History'));
const SMCStudio = lazy(() => import('./pages/SMCStudio'));
const SourceOfTruth = lazy(() => import('./pages/SourceOfTruth'));
const SchemaOrg = lazy(() => import('./pages/SchemaOrg'));
const PublisherRequest = lazy(() => import('./pages/PublisherRequest'));
const RobotsTxt = lazy(() => import('./pages/RobotsTxt'));
const Directory = lazy(() => import('./pages/Directory'));
const DirectoryEntity = lazy(() => import('./pages/DirectoryEntity'));
const Recharge = lazy(() => import('./pages/Recharge'));
const Projects = lazy(() => import('./pages/Projects'));
const Account = lazy(() => import('./pages/Account'));
const Clients = lazy(() => import('./pages/Clients'));
const Affiliation = lazy(() => import('./pages/Affiliation'));
const ContentWriter = lazy(() => import('./pages/ContentWriter'));
const Reputation = lazy(() => import('./pages/Reputation'));
const BotTracking = lazy(() => import('./pages/BotTracking'));
const Messages = lazy(() => import('./pages/Messages'));
const AlertsAEO = lazy(() => import('./pages/AlertsAEO'));
const MissionOrders = lazy(() => import('./pages/MissionOrders'));
const BlogOptimizer = lazy(() => import('./pages/BlogOptimizer'));
const AiResponseLayer = lazy(() => import('./pages/AiResponseLayer'));
const LlmsTxtGenerator = lazy(() => import('./pages/LlmsTxtGenerator'));
const AnswerFirstAudit = lazy(() => import('./pages/AnswerFirstAudit'));
const AiCitationSimulator = lazy(() => import('./pages/AiCitationSimulator'));
const EeatBuilder = lazy(() => import('./pages/EeatBuilder'));
const AiMonitoring = lazy(() => import('./pages/AiMonitoring'));
const Integrations = lazy(() => import('./pages/Integrations'));
const ApiDeveloper = lazy(() => import('./pages/ApiDeveloper'));

// V3 — Citation Verification Engine pages
const CitationDashboardPage = lazy(() => import('./pages/v3/CitationDashboardPage'));
const TrackedQueriesPage = lazy(() => import('./pages/v3/TrackedQueriesPage'));
const CitationDetailPage = lazy(() => import('./pages/v3/CitationDetailPage'));
const BenchmarkPage = lazy(() => import('./pages/v3/BenchmarkPage'));
const AlertsPage = lazy(() => import('./pages/v3/AlertsPage'));
const AlertSettingsPage = lazy(() => import('./pages/v3/AlertSettingsPage'));
const MonthlyReportPage = lazy(() => import('./pages/v3/MonthlyReportPage'));
const CalibrationPage = lazy(() => import('./pages/v3/CalibrationPage'));

import { AlertTriangle, X, ArrowUp, Plus } from 'lucide-react';
import { I18nProvider, useTranslation } from './i18n';

// Layout components (Vercel Dashboard style)
import AppShell from './components/layout/AppShell';
import type { Section } from './components/layout/TopNav';
import { getSectionForPage } from './components/layout/AppSidebar';

// Extracted components
import { Toast, ToastContext, ToastContainer } from './components/ToastSystem';
export { useToast } from './components/ToastSystem';
import CommandPalettePanel from './components/CommandPalette';
import ShortcutsModal from './components/ShortcutsModal';
import OnboardingModal from './components/OnboardingModal';

// Animated number hook for smooth credit transitions
const useAnimatedNumber = (value: number, duration = 600) => {
  const [display, setDisplay] = useState(value);
  const prevValue = useRef(value);
  useEffect(() => {
    if (prevValue.current === value) return;
    const start = prevValue.current;
    const diff = value - start;
    const startTime = performance.now();
    const animate = (now: number) => {
      const progress = Math.min((now - startTime) / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplay(Math.round(start + diff * eased));
      if (progress < 1) requestAnimationFrame(animate);
    };
    requestAnimationFrame(animate);
    prevValue.current = value;
  }, [value, duration]);
  return display;
};

const PLAN_LIMITS = {
  free: 1,
  pro: 3,
  enterprise: 1000
};

type ViewName = 'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking' | 'mission-orders' | 'blog-optimizer' | 'ai-response-layer' | 'llms-txt' | 'answer-first-audit' | 'ai-citation-simulator' | 'eeat-builder' | 'ai-monitoring' | 'integrations' | 'api-developer' | 'citation-dashboard' | 'tracked-queries' | 'citation-detail' | 'benchmark' | 'v3-alerts' | 'alert-settings' | 'monthly-report' | 'calibration';

const App: React.FC = () => {
  return (
    <I18nProvider>
      <AppContent />
    </I18nProvider>
  );
};

const AppContent: React.FC = () => {
  const { t } = useTranslation();

  // ── Toast system ──
  const [toasts, setToasts] = useState<Toast[]>([]);
  const showToast = useCallback((type: Toast['type'], message: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, type, message }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3500);
  }, []);
  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  // ── 2-level routing: section + page ──
  const [currentView, setCurrentView] = useState<ViewName>('home');
  const [activeSection, setActiveSection] = useState<Section>('dashboard');
  const [viewHistory, setViewHistory] = useState<string[]>([]);
  const [refreshKey, setRefreshKey] = useState(0);
  const [pageKey, setPageKey] = useState(0);

  // ── Data state ──
  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
  const [history, setHistory] = useState<AnalysisResult[]>([]);

  useEffect(() => {
    const loadedHistory = db.getAll();
    setHistory(loadedHistory);
  }, []);

  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]);
  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);

  const [megaStatus, setMegaStatus] = useState<MegaGenerationStatus>('idle');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');

  // ── Layout state ──
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

import React from "react";
import Link from "next/link";
import { 
  LayoutDashboard, 
  FolderOpen, 
  ScanLine, 
  Settings, 
  LogOut,
  CreditCard
} from "lucide-react";
import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";

export default async function AppLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    redirect('/login');
  }

  return (
    <div className="flex min-h-screen">
      {/* Sidebar */}
      <aside className="w-64 border-r border-white/10 bg-black/40 hidden md:flex flex-col sticky top-0 h-screen">
        <div className="p-6 border-b border-white/10">
          <div className="flex items-center gap-2 font-bold text-xl">
             <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center text-black font-serif">C</div>
             CitedBy.ai
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <Link href="/app" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <LayoutDashboard size={20} />
            <span className="font-medium">Tableau de bord</span>
          </Link>
          <Link href="/app/projects" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <FolderOpen size={20} />
            <span className="font-medium">Projets</span>
          </Link>
          <div className="my-4 border-t border-white/5"></div>
          <Link href="/app/settings/billing" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <CreditCard size={20} />
            <span className="font-medium">Abonnement</span>
          </Link>
          <Link href="/app/settings" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <Settings size={20} />
            <span className="font-medium">Paramètres</span>
          </Link>
        </nav>

        <div className="p-4 border-t border-white/10">
          <div className="flex items-center gap-3 px-4 py-2">
            <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center text-xs font-bold text-primary">
              {user.email?.[0].toUpperCase()}
            </div>
            <div className="overflow-hidden">
              <p className="text-sm font-medium truncate">{user.email}</p>
              <p className="text-xs text-gray-500">Plan Starter</p>
            </div>
          </div>
          <form action="/auth/signout" method="post">
            <button className="w-full mt-2 flex items-center gap-2 px-4 py-2 text-xs text-red-400 hover:text-red-300 transition-colors">
              <LogOut size={14} /> Déconnexion
            </button>
          </form>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        {children}
      </main>
    </div>
  );
}

